  // ─── ABOUT ────────────────────────────────────────────────────────────────
  "about.eyebrow":  { lv: "Kas ir Floutings",  en: "What is Floating",   ru: "Что такое флоатинг" },
  "about.h2.1":     { lv: "Dziļākā Relaksācija,", en: "The Deepest Relaxation,", ru: "Глубочайшая Релаксация," },
  "about.h2.2":     { lv: "Ko Zina Zinātne",    en: "That Science Knows",  ru: "Которую Знает Наука" },
  "about.p1": { lv: "Floutings jeb sensorās izolācijas terapija ir ātrākā un dziļākā relaksācijas un meditācijas metode, kas mūsdienās ir zināma cilvēcei. Kamēr tradicionālā meditācija prasa gadus prakses, floutings ļauj sasniegt dziļu tēta viļņu stāvokli jau pirmajā seansā.", en: "Floating, or sensory deprivation therapy, is the fastest and deepest method of relaxation and meditation known today. While traditional meditation takes years of practice, floating allows you to reach a deep theta-wave state on your very first session.", ru: "Флоатинг, или терапия сенсорной депривации, — это самый быстрый и глубокий метод расслабления и медитации, известный на сегодняшний день. В то время как традиционная медитация требует лет практики, флоатинг позволяет достичь глубокого тета-волнового состояния уже с первого сеанса." },
  "about.p2": { lv: "Jūs guļat uz muguras īpaši projektētā kamerā, kur ūdens ir piesātināts ar Epsom sāli (magnija sulfātu) – 5 reizes blīvāks par jūras ūdeni. Ūdens temperatūra ir 36,8°C – precīzi atbilstoša ķermeņa temperatūrai, tāpēc dažu minūšu laikā zūd robeža starp ķermeni un ūdeni.", en: "You lie on your back in a specially designed cabin where the water is saturated with Epsom salt (magnesium sulfate) — 5 times denser than sea water. The water temperature is 36.8°C, precisely matching body temperature, so within minutes the boundary between body and water disappears.", ru: "Вы лежите на спине в специально спроектированной кабине, где вода насыщена солью Эпсома (сульфатом магния) — в 5 раз плотнее морской воды. Температура воды 36,8°C точно соответствует температуре тела, поэтому уже через несколько минут граница между телом и водой исчезает." },
  "about.p3": { lv: "Bez gravitācijas, bez skaņas, bez gaismas – smadzenes pāriet radošā tēta viļņu stāvoklī. Viena stunda flouting ir salīdzināma ar 4–6 stundām dziļa miega atjaunojošo efektu.", en: "Without gravity, sound, or light — the brain shifts into a creative theta-wave state. One hour of floating is comparable to the restorative effect of 4–6 hours of deep sleep.", ru: "Без гравитации, звука и света — мозг переходит в творческое тета-волновое состояние. Один час флоатинга сопоставим с восстановительным эффектом 4–6 часов глубокого сна." },
  "about.card1.title": { lv: "Bezsvara Stāvoklis",    en: "Weightless State",        ru: "Состояние Невесомости" },
  "about.card1.desc":  { lv: "Epsom sāls ūdens izolē ķermeni no gravitācijas. Visi muskuļi pilnībā atpūšas.", en: "Epsom salt water isolates the body from gravity. All muscles relax completely.", ru: "Солевой раствор изолирует тело от гравитации. Все мышцы полностью расслабляются." },
  "about.card2.title": { lv: "36.8°C Temperatūra",    en: "36.8°C Temperature",      ru: "Температура 36.8°C" },
  "about.card2.desc":  { lv: "Precīza ķermeņa temperatūra nozīmē, ka robeža starp ādu un ūdeni pazūd.", en: "Precise body temperature means the boundary between skin and water disappears.", ru: "Точная температура тела означает, что граница между кожей и водой исчезает." },
